CREATE POLICY "Users can view own trade charts" ON storage.objects FOR SELECT TO authenticated USING (bucket_id = 'trade-charts' AND auth.uid()::text = (storage.foldername(name))[1]);
CREATE POLICY "Users can upload own trade charts" ON storage.objects FOR INSERT TO authenticated WITH CHECK (bucket_id = 'trade-charts' AND auth.uid()::text = (storage.foldername(name))[1]);
CREATE POLICY "Users can update own trade charts" ON storage.objects FOR UPDATE TO authenticated USING (bucket_id = 'trade-charts' AND auth.uid()::text = (storage.foldername(name))[1]);
CREATE POLICY "Users can delete own trade charts" ON storage.objects FOR DELETE TO authenticated USING (bucket_id = 'trade-charts' AND auth.uid()::text = (storage.foldername(name))[1]);